#include <iostream>
#include <vector>
#include <string>
using namespace std;

vector<string> todoList;

void showMenu()
{
    cout << "\n=== YAPILACAKLAR LISTESI ===" << endl;
    cout << "1. Gorev Ekle" << endl;
    cout << "2. Gorevleri Listele" << endl;
    cout << "3. Gorev Sil" << endl;
    cout << "4. Cikis" << endl;
}

void addTask(string task)
{
    todoList.push_back(task);
    cout << "Eklendi: '" << task << "'" << endl;
}

void listTasks()
{
    if (todoList.empty())
    {
        cout << "Liste bos." << endl;
        return;
    }

    for (int i = 0; i < todoList.size(); i++)
    {
        cout << (i + 1) << ". " << todoList[i] << endl;
    }
}

void removeTask(int index)
{
    if (index >= 0 && index < todoList.size())
    {
        cout << "Silindi: '" << todoList[index] << "'" << endl;
        todoList.erase(todoList.begin() + index);
    }
    else
    {
        cout << "Gecersiz numara." << endl;
    }
}

int main()
{
    showMenu();

    cout << "\n> Secim: 1" << endl;
    addTask("Markete git");

    cout << "\n> Secim: 1" << endl;
    addTask("Kod yaz");

    cout << "\n> Secim: 1" << endl;
    addTask("Spor yap");

    cout << "\n> Secim: 2" << endl;
    listTasks();

    cout << "\n> Secim: 3 (1. gorevi sil)" << endl;
    removeTask(0);

    cout << "\n> Secim: 2" << endl;
    listTasks();

    cout << "\n> Secim: 4" << endl;
    cout << "Programdan cikiliyor..." << endl;

    return 0;
}
